#include <vector>
#include <climits>
#include <algorithm>
using namespace std;

int minCoins(vector<int>& coins, int amount) {
    vector<int> dp(amount + 1, INT_MAX);
    dp[0] = 0;

    for (int i = 1; i <= amount; i++) {
        for (int j = 0; j < coins.size(); j++) {
            if (coins[j] <= i) {
                if (dp[i - coins[j]] != INT_MAX) {
                    dp[i] = min(dp[i], dp[i - coins[j]] + 1);
                }
            }
        }
    }

    return dp[amount] == INT_MAX ? -1 : dp[amount];
}
```

The `minCoins` function initializes a dynamic programming array `dp` with size `amount + 1` and sets all values to `INT_MAX` except for `dp[0]` which is set to 0. It then iterates through each amount from 1 to the target amount, and for each amount, it iterates through each coin denomination. If the current coin denomination is less than or equal to the current amount, it updates `dp[i]` with the minimum of its current value and `dp[i - coins[j]] + 1`. Finally, it returns `dp[amount]` if it is not `INT_MAX`, otherwise, it returns -1.

