```javascript
class TaskAllocator {
  constructor(people, week) {
    this.people = people;
    this.week = week;
  }

  allocateTasks(tasks) {
    const allocation = Array.from({ length: this.people }, () => Array(this.week).fill(0));
    let totalTasks = tasks.reduce((acc, val) => acc + val, 0);
    let tasksPerPerson = Math.floor(totalTasks / (this.people * this.week));
    let remainingTasks = totalTasks % (this.people * this.week);

    for (let w = 0; w < this.week; w++) {
      for (let p = 0; p < this.people; p++) {
        if (remainingTasks > 0) {
          allocation[p][w] = tasksPerPerson + 1;
          remainingTasks--;
        } else {
          allocation[p][w] = tasksPerPerson;
        }
      }
    }
    return allocation;
  }
}
```

