import java.util.ArrayList;
import java.util.List;

public class ImageResizer {
    public List<String> resizeImages(List<String> imageDimensions, int max) {
        List<String> resizedDimensions = new ArrayList<>();
        for (String dimension : imageDimensions) {
            String[] parts = dimension.split("x");
            int width = Integer.parseInt(parts[0]);
            int height = Integer.parseInt(parts[1]);
            if (height > max) {
                int newHeight = max;
                int newWidth = (int) Math.round((double) width * max / height);
                resizedDimensions.add(newWidth + "x" + newHeight);
            } else {
                resizedDimensions.add(dimension);
            }
        }
        return resizedDimensions;
    }

    public static void main(String[] args) {
        ImageResizer resizer = new ImageResizer();
        List<String> imageDimensions = List.of("800x600", "1200x900", "400x300");
        int max = 600;
        List<String> resized = resizer.resizeImages(imageDimensions, max);
        System.out.println(resized);  // Output: ["800x600", "600x450", "400x300"]
    }
}
```

