```java
public class BlackScholesOptionPricing {
    public static double[] calculateOptionPrices(double[] strikes, double S_t, double r, double t, double sigma) {
        final int nStrikes = strikes.length;
        final double[] res = new double[nStrikes];

        for (int i = 0; i < nStrikes; i++) {
            double d1 = (1 / (sigma * Math.sqrt(t))) * (Math.log(S_t / strikes[i]) + (r + (Math.pow(sigma, 2) / 2)) * t);
            double d2 = d1 - sigma * Math.sqrt(t);
            res[i] = S_t * cumulativeDistributionFunction(d1) - strikes[i] * Math.exp(-r * t) * cumulativeDistributionFunction(d2);
        }

        return res;
    }

    private static double cumulativeDistributionFunction(double x) {
        return 0.5 * (1 + erf(x / Math.sqrt(2)));
    }

    private static double erf(double z) {
        double t = 1.0 / (1.0 + 0.5 * Math.abs(z));

        // Use Horner's method to evaluate the rational function
        double ans = 1 - t * Math.exp(-z * z - 1.26551223 +
                t * (1.00002368 +
                        t * (0.37409196 +
                                t * (0.09678418 +
                                        t * (-0.18628806 +
                                                t * (0.27886807 +
                                                        t * (-1.13520398 +
                                                                t * (1.48851587 +
                                                                        t * (-0.82215223 +
                                                                                t * (0.17087277))))))))));
        return z >= 0 ? ans : -ans;
    }
}
```

