use std::collections::HashSet;

struct Player {
    uuid: String,
    // Other player information
}

enum Action {
    Add(Vec<Player>),
    Remove(Vec<Player>),
}

fn update_tablist(tablist_members: &mut HashSet<String>, actions: &[Action]) {
    for action in actions {
        match action {
            Action::Add(players) => {
                for player in players.iter() {
                    tablist_members.insert(player.uuid.clone());
                }
            }
            Action::Remove(players) => {
                for player in players.iter() {
                    tablist_members.remove(&player.uuid);
