def organize_packages(packages: list) -> dict:
    organized = {}
    for package in packages:
        name = package["name"]
        version = package["version"]
        if name in organized:
            organized[name].append(version)
        else:
            organized[name] = [version]
    return organized

def calculate_total_size(organized_packages: dict, package_name: str) -> int:
    total_size = 0
    if package_name in organized_packages:
        versions = organized_packages[package_name]
        for package in packages:
            if package["name"] in versions:
                total_size += package["size"]
    return total_size
```

