class InputDataGenerator:
    def __init__(self, batch_size):
        self.batch_size = batch_size
        self.input_data = {}

    def generate_input_data(self, input_nodes):
        for input_node in input_nodes:
            input_shape = []
            for i, dim in enumerate(input_node.type.tensor_type.shape.dim):
                if i == 0 and dim.dim_value <= 0 and self.batch_size != 0:
                    input_shape.append(self.batch_size)
                else:
                    input_shape.append(dim.dim_value)
            if 1 == input_node.type.tensor_type.elem_type:
                self.input_data[input_node.name] = np.random.randn(*input_shape).astype(np.float32)
            elif 7 == input_node.type.tensor_type.elem_type:
                self.input_data[input_node.name] = np.random.randint(0, 3, input_shape).astype(np.int64)
            elif 9 == input_node.type.tensor_type.elem_type:
                self.input_data[input_node.name] = np.random.choice([True, False], size=input_shape)
