// Define the FunctionAttribute enum
enum FunctionAttribute {
    case constructor
    case getter
    case setter
    case virtual
}

// Define the FunctionAttributes protocol
protocol FunctionAttributes {
    var isConstructor: Bool { get }
    var isGetter: Bool { get }
    var isSetter: Bool { get }
    func hasVirtualAttribute() -> Bool
}

// Implement the FunctionAttributes protocol in a struct Function
struct Function: FunctionAttributes {
    var attributes: Set<FunctionAttribute>

    var isConstructor: Bool { attributes.contains(.constructor) }
    var isGetter: Bool { attributes.contains(.getter) }
    var isSetter: Bool { attributes.contains(.setter) }

    func hasVirtualAttribute() -> Bool {
        return attributes.contains(.virtual)
    }
}

// Create the checkVirtualAttribute function
func checkVirtualAttribute(_ function: Function) -> Bool {
    return function.hasVirtualAttribute()
}
```

This solution defines a protocol `FunctionAttributes` with properties and methods to determine specific attributes of a function. It also implements the protocol in a struct `Function` and provides a function to check if a given function has a virtual attribute.

