#include <stack>
#include <string>

bool isProperlyNested(std::string braces) {
    std::stack<char> stack;
    for (char brace : braces) {
        if (brace == '{') {
            stack.push(brace);
        } else if (brace == '}') {
            if (stack.empty() || stack.top() != '{') {
                return false;
            }
            stack.pop();
        }
    }
    return stack.empty();
}
