import os

def calculate_total_size(directory_path):
    total_size = 0
    for root, _, files in os.walk(directory_path):
        for file in files:
            file_path = os.path.join(root, file)
            if not os.path.islink(file_path):
                total_size += os.path.getsize(file_path)
            else:
                link_target = os.readlink(file_path)
                if os.path.isfile(link_target):
                    total_size += os.path.getsize(link_target)
    return total_size

# Example usage
directory_path = 'main_directory'
print(calculate_total_size(directory_path))  # Output: 750
