type FoveaHost = string;
interface IDestroyable {
    destroy(): void;
}

class WeakMultiMap<K extends object, V extends object> {
    private map: WeakMap<K, Set<V>>;

    constructor() {
        this.map = new WeakMap();
    }

    set(key: K, value: V): void {
        let values = this.map.get(key);
        if (!values) {
            values = new Set();
            this.map.set(key, values);
        }
        values.add(value);
    }

    get(key: K): V[] | undefined {
        const values = this.map.get(key);
        return values ? Array.from(values) : undefined;
    }

    delete(key: K): boolean {
        return this.map.delete(key);
    }

    clear(): void {
        this.map = new WeakMap();
    }
}

type ConstructedHostsMap = WeakMultiMap<FoveaHost, IDestroyable>;

function constructHostsMap(hosts: FoveaHost[], destroyables: IDestroyable[]): ConstructedHostsMap {
    const hostsMap = new WeakMultiMap<FoveaHost, IDestroyable>();
    hosts.forEach((host, index) => {
        hostsMap.set(host, destroyables[index]);
    });
    return hostsMap;
}
```

