using System;
using System.Text.Json;
using System.Text.Json.Serialization;

namespace NebSharp.Types
{
    [AttributeUsage(AttributeTargets.Property)]
    public class JsonPathAttribute : Attribute
    {
        public string Path { get; }

        public JsonPathAttribute(string path)
        {
            Path = path;
        }
    }

    public class SampleClass
    {
        [JsonPath("$.name")]
        public string Name { get; set; }

        [JsonPath("$.age")]
        public int Age { get; set; }
    }

    public class JsonPathSerializer
    {
        public string SerializeObjectWithJsonPath(object obj)
        {
            var options = new JsonSerializerOptions
            {
                Converters = { new JsonPathConverter() }
            };
            return JsonSerializer.Serialize(obj, options);
        }

        public T DeserializeObjectWithJsonPath<T>(string json)
        {
            var options = new JsonSerializerOptions
            {
                Converters = { new JsonPathConverter() }
            };
            return JsonSerializer.Deserialize<T>(json, options);
        }
    }

    public class JsonPathConverter : JsonConverter<object>
    {
        public override object Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
        {
            throw new NotImplementedException("Deserialization with JSONPath is not implemented in this example.");
        }

        public override void Write(Utf8JsonWriter writer, object value, JsonSerializerOptions options)
        {
            var type = value.GetType();
            writer.WriteStartObject();
            foreach (var property in type.GetProperties())
            {
                var jsonPathAttribute = (JsonPathAttribute)Attribute.GetCustomAttribute(property, typeof(JsonPathAttribute));
                if (jsonPathAttribute != null)
                {
                    writer.WritePropertyName(jsonPathAttribute.Path);
                    writer.WriteValue(property.GetValue(value));
                }
            }
            writer.WriteEndObject();
        }
    }
}
```

In this solution, a custom attribute `JsonPathAttribute` is defined to specify the JSONPath expression for a property. The `SampleClass` demonstrates the usage of this attribute on properties. The `JsonPathSerializer` class provides methods for serializing and deserializing objects using the specified JSONPath expressions. The `JsonPathConverter` is used to customize the serialization process based on the JSONPath attributes applied to the properties. Note that deserialization with JSONPath is not implemented in this example.

