from typing import List
import heapq

def kSmallestPairs(nums1: List[int], nums2: List[int], k: int) -> List[List[int]]:
    if not nums1 or not nums2:
        return []

    heap = []
    for n1 in nums1:
        for n2 in nums2:
            if len(heap) < k:
                heapq.heappush(heap, (-n1 - n2, [n1, n2]))
            else:
                if n1 + n2 < -heap[0][0]:
                    heapq.heappop(heap)
                    heapq.heappush(heap, (-n1 - n2, [n1, n2]))

    return [pair for _, pair in heap]
```

