def longestPalindromeSubseq(s: str) -> int:
    def helper(b, e):
        if b > e:
            return 0
        if b == e:
            return 1
        if s[b] == s[e]:
            return helper(b + 1, e - 1) + 2
        return max(helper(b + 1, e), helper(b, e - 1))

