import psycopg2

class ConnectionError(Exception):
    pass

class QueryExecutionError(Exception):
    pass

class PostgresConnection:
    def __init__(self, username, password, database, host, port):
        self.username = username
        self.password = password
        self.database = database
        self.host = host
        self.port = port
        self.connection = None

    def connect(self):
        try:
            self.connection = psycopg2.connect(
                user=self.username,
                password=self.password,
                database=self.database,
                host=self.host,
                port=self.port
            )
        except psycopg2.Error as e:
            raise ConnectionError(f"Failed to connect to the database: {e}")

    def execute_query(self, query):
        if not self.connection:
            raise ConnectionError("Connection is not established")
        try:
            cursor = self.connection.cursor()
            cursor.execute(query)
            result = cursor.fetchall()
            cursor.close()
            return result
        except psycopg2.Error as e:
            raise QueryExecutionError(f"Failed to execute the query: {e}")

    def close_connection(self):
        if self.connection:
            self.connection.close()
            self.connection = None
```

The `PostgresConnection` class is implemented with error handling for connection establishment and query execution. It uses the `psycopg2` library to interact with the PostgreSQL database. The class provides methods to connect to the database, execute queries, and close the connection, while handling potential errors by raising custom exceptions.

