            for control in rightControls {
                addSubview(control)
                control.translatesAutoresizingMaskIntoConstraints = false
                if let previousControl = subviews.last?.previousSibling {
                    control.topAnchor.constraint(equalTo: previousControl.bottomAnchor, constant: 8).isActive = true
                } else {
                    control.topAnchor.constraint(equalTo: topAnchor, constant: 8).isActive = true
                }
                control.leadingAnchor.constraint(equalTo: centerXAnchor, constant: 8).isActive = true
