    sequences = []
    with open(file_name, 'r') as file:
        sequence_id = None
        sequence = ''
        for line in file:
            line = line.strip()
            if line.startswith('>'):
                if sequence_id is not None:
                    sequences.append((sequence_id, sequence))
                sequence_id = line[1:]
                sequence = ''
            else:
                sequence += line
        if sequence_id is not None:
            sequences.append((sequence_id, sequence))
    return sequences

def process_fasta_files(files: List[str]) -> Dict[str, str]:
