class Library:
    def __init__(self):
        self.books = {}
        self.borrowed = {}

    def add_book(self, title):
        if title in self.books:
            print(f"{title} is already in the library.")
        else:
            self.books[title] = True

    def borrow_book(self, title, user):
        if title in self.books and self.books[title]:
            self.books[title] = False
            if user in self.borrowed:
                self.borrowed[user].append(title)
            else:
                self.borrowed[user] = [title]
            print(f"{user} has borrowed {title}.")
        elif title in self.books and not self.books[title]:
            print(f"{title} is already borrowed by someone else.")
        else:
            print(f"{title} is not available in the library.")

    def return_book(self, title):
        if title in self.books:
            self.books[title] = True
            for user, books in self.borrowed.items():
                if title in books:
                    books.remove(title)
                    print(f"{title} has been returned.")
                    break
        else:
            print(f"{title} is not a valid book.")

    def available_books(self):
        return [title for title, available in self.books.items() if available]

    def borrowed_books(self):
        return self.borrowed
```
This `Library` class provides the required functionality for managing a library's collection of books and the borrowing and returning of books by users.

