from datetime import datetime, timedelta
from typing import Optional

class TaskLifecycle:
    def __init__(self, creation_time: datetime, destruction_time: datetime):
        self.creation_time = creation_time
        self.start_time: Optional[datetime] = None
        self.end_time: Optional[datetime] = None
        self.destruction_time = destruction_time
        self.execution_duration: Optional[int] = None

    def start_execution(self, start_time: datetime) -> None:
        if start_time < self.creation_time or start_time > self.destruction_time:
            raise ValueError("Invalid start time")
        if self.start_time is not None or self.end_time is not None:
            raise ValueError("Execution already started or ended")
        self.start_time = start_time

    def end_execution(self, end_time: datetime) -> None:
        if end_time < self.creation_time or end_time > self.destruction_time:
            raise ValueError("Invalid end time")
        if self.start_time is None:
            raise ValueError("Execution not started")
        if self.end_time is not None:
            raise ValueError("Execution already ended")
        self.end_time = end_time
        self.execution_duration = int((self.end_time - self.start_time).total_seconds())

    def get_execution_duration(self) -> Optional[int]:
        if self.execution_duration is None:
            raise ValueError("Execution duration not available")
        return self.execution_duration
```

This `TaskLifecycle` class allows for the management of task lifecycle, ensuring that the task is executed within the specified time frame and providing the execution duration when required.

