enum OptionType {
  BOOLEAN,
  STRING,
  NUMBER,
}

class Option {
  name: string;
  type: OptionType;
  defaultValue: boolean | string | number;
  command?: string;
  expand?: string;
  private value: boolean | string | number;

  constructor({
    name,
    type = OptionType.BOOLEAN,
    default: defaultValue = false,
    command,
    expand,
  }: {
    name: string;
    type?: OptionType;
    default?: boolean | string | number;
    command?: string;
    expand?: string;
  }) {
    this.name = name;
    this.type = type;
    this.defaultValue = defaultValue !== undefined ? defaultValue : this.getDefaultValue();
    this.command = command;
    this.expand = expand;
    this.value = this.defaultValue;
  }

  private getDefaultValue(): boolean | string | number {
    switch (this.type) {
      case OptionType.BOOLEAN:
        return false;
      case OptionType.STRING:
        return '';
      case OptionType.NUMBER:
        return 0;
      default:
        throw new Error('Invalid option type');
    }
  }

  getValue(): boolean | string | number {
    return this.value;
  }

  setValue(value: boolean | string | number): void {
    if (typeof value === typeof this.defaultValue) {
      this.value = value;
    } else {
      throw new Error('Invalid value type for the option');
    }
  }
}
```

