import hmac
import os
import random
import string

class SecurePasswordManager:
    def __init__(self):
        self.secret_key = os.urandom(16)  # Generate a secret key for HMAC

    def generate_password(self, length: int) -> str:
        characters = string.ascii_letters + string.digits
        return ''.join(random.choice(characters) for _ in range(length))

    def hash_password(self, password: str) -> str:
        return hmac.new(self.secret_key, password.encode(), 'sha256').hexdigest()

    def verify_password(self, password: str, hashed_password: str) -> bool:
        return hmac.compare_digest(hashed_password, self.hash_password(password))

# Demonstration of using SecurePasswordManager
password_manager = SecurePasswordManager()
password = password_manager.generate_password(12)
hashed_password = password_manager.hash_password(password)
print(f"Generated Password: {password}")
print(f"Hashed Password: {hashed_password}")
print("Verification Result:", password_manager.verify_password(password, hashed_password))
```

In this solution, the `SecurePasswordManager` class is implemented with the required functionalities. The `os.urandom(16)` call generates a 16-byte secret key for HMAC. The `generate_password` method creates a random password of the specified length, the `hash_password` method computes the HMAC hash of the password using the secret key, and the `verify_password` method compares the provided password's hash with the stored hash using `hmac.compare_digest` for secure comparison. Finally, a demonstration of using the `SecurePasswordManager` class is provided to generate a password, hash it, and verify it.

