struct ServiceRegistry {
    onstart: Vec<Pin<Box<dyn Future<Output = ()> + 'static>>>,
}

impl ServiceRegistry {
    fn new() -> Self {
        ServiceRegistry { onstart: Vec::new() }
    }

    fn register_service<F>(&mut self, fut: F)
    where
        F: Future<Output = ()> + 'static,
    {
        self.onstart.push(Box::pin(fut));
    }

    async fn start_services(&mut self) {
        for fut in &mut self.onstart {
            fut.await;
        }
    }
}

