    private Dictionary<string, List<Delegate>> eventListeners;

    public EventDispatcher()
    {
        eventListeners = new Dictionary<string, List<Delegate>>();
    }

    public void AddListener(string eventName, Delegate eventHandler)
    {
        if (!eventListeners.ContainsKey(eventName))
        {
            eventListeners[eventName] = new List<Delegate>();
        }
        eventListeners[eventName].Add(eventHandler);
    }

    public void RemoveListener(string eventName, Delegate eventHandler)
    {
        if (eventListeners.ContainsKey(eventName))
        {
            eventListeners[eventName].Remove(eventHandler);
        }
    }

    public void Dispatch(string eventName)
    {
        if (eventListeners.ContainsKey(eventName))
        {
            foreach (var handler in eventListeners[eventName])
            {
                handler.DynamicInvoke();
            }
        }
    }
}
