video_info_dict = {}
vd_epoch = -1

def add_video(title, duration, upload_time):
    global vd_epoch
    video_info_dict[title] = {'duration': duration, 'upload_time': upload_time}
    vd_epoch = max(vd_epoch, upload_time)

def update_duration(title, new_duration):
    if title in video_info_dict:
        video_info_dict[title]['duration'] = new_duration
        vd_epoch = max(vd_epoch, video_info_dict[title]['upload_time'])

def get_longest_video_title():
    longest_duration = max(video_info_dict.values(), key=lambda x: x['duration'])['duration']
    longest_videos = [title for title, info in video_info_dict.items() if info['duration'] == longest_duration]
    return longest_videos[0] if longest_videos else None

def get_videos_uploaded_after(upload_time):
    return [title for title, info in video_info_dict.items() if info['upload_time'] > upload_time]
```

