        self._dicDefault = {}  # Default permissions for all groups
        self._dicUser = None  # User-specific permissions

    def set_permission(self, group_name, file_path, permission_level):
        foundGrName = ''
        for grName in [group_name, '']:
            if grName in self._dicDefault:
                foundGrName = grName
                break
        else:
            continue  # Only executed if the inner loop did NOT break
        break  # Only executed if the inner loop DID break

        if '' == foundGrName:
            dic = self._dicDefault
        else:
            if self._dicUser is None:
                self._dicUser = dict()
            if foundGrName not in self._dicUser:
                self._dicUser[foundGrName] = dict()
            dic = self._dicUser[foundGrName]
        dic[file_path] = permission_level

    def get_permission(self, group_name, file_path):
        if self._dicUser is not None and group_name in self._dicUser and file_path in self._dicUser[group_name]:
            return self._dicUser[group_name][file_path]
        elif group_name in self._dicDefault and file_path in self._dicDefault:
