class IndexedTransformer:

    def __init__(self, transformer: TimeSeriesTransformer, padding: int, step: int):
        self.transformer = transformer
        self.padding = padding
        self.step = step

    def transform_indexed_data(self, data: np.ndarray) -> dict:
        transformed_data = self.transformer.transform(data)  # Apply transformation using TimeSeriesTransformer
        indexed_data = {}
        index = 0
        while index + self.padding < len(transformed_data):
            indexed_data[index] = transformed_data[index:index + self.padding]
            index += self.step
        return indexed_data
