class MessagingSystem:
    def __init__(self, broker_address, port):
        self.client = mqtt.Client()
        self.broker_address = broker_address
        self.port = port

    def connect(self):
        self.client.connect(self.broker_address, self.port, 60)

    def disconnect(self):
        self.client.disconnect()
        self.client.loop_stop(force=False)

    def publish(self, topic, data):
        topic = str(topic, encoding='utf-8')  # paho wants a string
        self.client.publish(topic, data)

    def subscribe(self, topic):
        self.client.subscribe(topic)

    def on_message(self, client, userdata, message):
        # Handle incoming messages here
        print(f"Received message on topic {message.topic}: {str(message.payload, 'utf-8')}")

    def on_connect(self, client, userdata, flags, rc):
        # Handle connection events here
        if rc == 0:
            print("Connected to broker")
        else:
            print(f"Connection failed with result code {rc}")

    def on_disconnect(self, client, userdata, rc):
        # Handle disconnection events here
        if rc != 0:
            print(f"Unexpected disconnection with result code {rc}")

    def on_subscribe(self, client, userdata, mid, granted_qos):
        # Handle subscription events here
        print(f"Subscribed to topic with message id {mid}")

    def on_log(self, client, userdata, level, buf):
        # Handle logging events here
        print(f"Log: {buf}")

    def start(self):
        self.client.on_message = self.on_message
        self.client.on_connect = self.on_connect
        self.client.on_disconnect = self.on_disconnect
        self.client.on_subscribe = self.on_subscribe
        self.client.on_log = self.on_log
        self.client.loop_start()
