from typing import List, Dict, Union, Tuple
import numpy as np

def perform_data_augmentation(choices: List[int], params: Dict[str, Union[bool, int]], images_indexes_per_class: Dict[int, List[int]]) -> List[Tuple[int, int]]:
    augmented_choices = []

    if params['shuffle']:
        np.random.shuffle(choices)

    for choice in choices:
        for _ in range(params['duplicate_n_times']):
            selected_index = int(np.random.choice(images_indexes_per_class[choice]))
            augmented_choices.append((choice, selected_index))

    return augmented_choices
