public class RemoteObjectsRecord implements IRemoteObjectsRecord {
    private List<Object> registeredObjects;

    public RemoteObjectsRecord() {
        this.registeredObjects = new ArrayList<>();
    }

    @Override
    public void Register(Object obj) {
        registeredObjects.add(obj);
    }

    @Override
    public <T> void DestroyByType(Predicate<T> condition) {
        List<Object> objectsToRemove = new ArrayList<>();
        for (Object obj : registeredObjects) {
            if (obj instanceof T && condition.test((T) obj)) {
                objectsToRemove.add(obj);
            }
        }
        registeredObjects.removeAll(objectsToRemove);
    }
}
