import UIKit

final class ListTableViewController: UITableViewController {

  // MARK: - Property

  private let list: [String] = ["Normal", "Scroll"]
  private var segmentedControl: UISegmentedControl!
  private var items: [String] = []

  // MARK: - Life Cycle

  override func viewDidLoad() {
    super.viewDidLoad()

    self.navigationItem.title = "UPsSegmented"

    // Create and configure the segmented control
    segmentedControl = UISegmentedControl(items: list)
    segmentedControl.selectedSegmentIndex = 0
    segmentedControl.addTarget(self, action: #selector(segmentedControlValueChanged(_:)), for: .valueChanged)

    // Add the segmented control to the table view header
    tableView.tableHeaderView = segmentedControl

    // Initialize the table view content based on the default segment
    updateTableViewContent(forSegment: segmentedControl.selectedSegmentIndex)
  }

  // MARK: - Segmented Control Action

  @objc private func segmentedControlValueChanged(_ sender: UISegmentedControl) {
    updateTableViewContent(forSegment: sender.selectedSegmentIndex)
  }

  // MARK: - Table View Content Update

  private func updateTableViewContent(forSegment segmentIndex: Int) {
    switch segmentIndex {
    case 0: // "Normal" segment
      items = ["Item 1", "Item 2", "Item 3"]
    case 1: // "Scroll" segment
      items = Array(repeating: "Scrollable Item", count: 20)
    default:
      break
    }
    tableView.reloadData()
  }

  // MARK: - Table View Data Source

  override func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
    return items.count
  }

  override func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
    let cell = tableView.dequeueReusableCell(withIdentifier: "Cell", for: indexPath)
    cell.textLabel?.text = items[indexPath.row]
    return cell
  }
}
