      return
    }
    guard let gifSource = CGImageSourceCreateWithURL(gifURL as CFURL, nil) else {
      print("Error creating GIF source")
      return
    }
    let gifDuration = gifSource.getGifDuration()
    let gifImages = gifSource.getGifImages()
    gifView.animationImages = gifImages
    gifView.animationDuration = gifDuration
    gifView.startAnimating()
  }

  func setMessage(_ message: String) {
    messageLbl.text = message
  }

  func show() {
    self.isHidden = false
  }

  func hide() {
    self.isHidden = true
  }
}

extension CGImageSource {
  func getGifDuration() -> TimeInterval {
    let gifProperties = CGImageSourceCopyPropertiesAtIndex(self, 0, nil) as Dictionary?
    if let gifDictionary = gifProperties {
      if let delayTimeUnclampedProp = gifDictionary[kCGImagePropertyGIFUnclampedDelayTime] as? TimeInterval {
        return delayTimeUnclampedProp
      } else if let delayTimeProp = gifDictionary[kCGImagePropertyGIFDelayTime] as? TimeInterval {
        return delayTimeProp
      }
    }
    return 0.0
  }

  func getGifImages() -> [UIImage] {
    let imageCount = CGImageSourceGetCount(self)
    var images = [UIImage]()
    for i in 0..<imageCount {
      if let cgImage = CGImageSourceCreateImageAtIndex(self, i, nil) {
        images.append(UIImage(cgImage: cgImage))
      }
    }
    return images
  }
}
