class Result<T, E> {
    private value: T | E;
    private isError: boolean;

    private constructor(value: T | E, isError: boolean) {
        this.value = value;
        this.isError = isError;
    }

    static ok<T, E>(value: T): Result<T, E> {
        return new Result<T, E>(value, false);
    }

    static err<T, E>(value: E): Result<T, E> {
        return new Result<T, E>(value, true);
    }

    flatMap<U>(fn: (value: T) => Result<U, E>): Result<U, E> {
        if (this.isError) {
            return Result.err<U, E>(this.value as E);
        } else {
            return fn(this.value as T);
        }
    }

    expectErr(expectedErr: E): void {
        if (!this.isError || this.value !== expectedErr) {
            throw new Error(`Expected error: ${expectedErr}, but got: ${this.value}`);
        }
    }
}

// Example usage
const okResult = Result.ok<number, string>(10);
const errResult = Result.err<number, string>("Error message");

