```csharp
public class SqlDbExecutor : DbExecutorBase, IAsyncDbExecutor<ParameterizedQuery>, IDbTransactionProvider<SqlDbExecutor>
{
    private readonly IDbConnection _connection;

    public SqlDbExecutor(IDbConnection connection)
    {
        _connection = connection;
    }

    public async Task<TResult> ExecuteAsync<TResult>(ParameterizedQuery query)
    {
        using (var command = _connection.CreateCommand())
        {
            command.CommandText = query.Query;
            command.Parameters.AddRange(query.Parameters.ToArray());

            await _connection.OpenAsync();
            var result = await command.ExecuteScalarAsync();

            _connection.Close();

            return (TResult)Convert.ChangeType(result, typeof(TResult));
        }
    }

    public IDbTransactionProvider<SqlDbExecutor> BeginTransaction()
    {
        _connection.Open();
        var transaction = _connection.BeginTransaction();
        return new SqlDbTransactionProvider(_connection, transaction);
    }

    public void CommitTransaction(IDbTransactionProvider<SqlDbExecutor> transaction)
    {
        if (transaction is SqlDbTransactionProvider sqlTransactionProvider)
        {
            sqlTransactionProvider.Commit();
        }
    }
}

public class SqlDbTransactionProvider : IDbTransactionProvider<SqlDbExecutor>
{
    private readonly IDbConnection _connection;
    private readonly IDbTransaction _transaction;

    public SqlDbTransactionProvider(IDbConnection connection, IDbTransaction transaction)
    {
        _connection = connection;
        _transaction = transaction;
    }

    public void Commit()
    {
        _transaction.Commit();
        _connection.Close();
    }
}
```

