import subprocess
from daemon import Daemon
from subprocess import DEVNULL

class CommandError(Exception):
    CODE_EXECUTE = "cmd.execute"

class DaemonManager:
    def __init__(self):
        self.daemon_processes = []

    def spawn_daemon(self, cmd, stdout=DEVNULL, stderr=subprocess.STDOUT, cwd=None):
        proc = subprocess.Popen(cmd, cwd=cwd, stdout=stdout, stderr=stderr, close_fds=True)
        self.daemon_processes.append(proc)
        return proc.pid

    def terminate_daemon(self, pid):
        for proc in self.daemon_processes:
            if proc.pid == pid:
                proc.terminate()
                self.daemon_processes.remove(proc)
                return

    def check_status(self, pid):
        for proc in self.daemon_processes:
            if proc.pid == pid:
                if proc.poll() is None:
                    return "Running"
                else:
                    return "Terminated"
        return "PID not found"
```

This solution provides a `DaemonManager` class that manages daemon processes, allowing for spawning, terminating, and checking the status of the processes. The class utilizes the `subprocess` module to spawn and manage the daemon processes, and it maintains a list of active daemon processes for easy management.

