use std::fs::File;
use std::io::{BufRead, BufReader, Write, Result};

fn process_file(input_file_path: &str, output_file_path: &str, operation: fn(String) -> String) -> Result<()> {
    let input_file = File::open(input_file_path)?;
    let output_file = File::create(output_file_path)?;
    let input_reader = BufReader::new(input_file);
    let mut output_handle = std::io::LineWriter::new(output_file);

    for line in input_reader.lines() {
        let processed_line = operation(line?);
        writeln!(output_handle, "{}", processed_line)?;
    }

    output_handle.flush()?;

    Ok(())
}
