from enum import Enum

class DuelStatus(Enum):
    CANNOT_DUEL_WITH_YOURSELF = 1
    DUEL_SUCCESSFUL = 2

class DuelResult:
    def __init__(self, status, prize=None):
        self.status = status
        self.prize = prize

class DuelArena:
    def __init__(self, random_strategy):
        self.duels = {}
        self.random_strategy = random_strategy

    def add_or_make_duel(self, duel_id, challenger, prize, target):
        if challenger == target:
            return DuelResult(DuelStatus.CANNOT_DUEL_WITH_YOURSELF)

        if duel_id in self.duels:
            return self.get_duel_result(duel_id)

        self.duels[duel_id] = (challenger, prize, target)
        return DuelResult(DuelStatus.DUEL_SUCCESSFUL)

    def get_duel_result(self, duel_id):
        if duel_id in self.duels:
            challenger, prize, target = self.duels[duel_id]
            return DuelResult(DuelStatus.DUEL_SUCCESSFUL, prize)
        else:
            # Handle case when duel_id is not found
            return None

    def list_user_duels(self, user):
        user_duels = []
        for duel_id, (challenger, prize, target) in self.duels.items():
            if user == challenger or user == target:
                user_duels.append(duel_id)
