class WaiterManager:
    def __init__(self):
        self.waiters = {}

    def register_waiter(self, waiter_key, waiter_id):
        if waiter_key not in self.waiters:
            self.waiters[waiter_key] = set()
        self.waiters[waiter_key].add(waiter_id)

    def unregister_waiter(self, waiter_key, waiter_id):
        if waiter_key in self.waiters:
            if waiter_id in self.waiters[waiter_key]:
                self.waiters[waiter_key].remove(waiter_id)
                if len(self.waiters[waiter_key]) == 0:
                    del self.waiters[waiter_key]

    def notify_waiters(self, waiter_key):
        if waiter_key in self.waiters:
            for waiter_id in self.waiters[waiter_key]:
                # Notify the waiter with the specified key
                print(f"Notifying waiter {waiter_id} for key {waiter_key}")
        else:
            print(f"No waiters registered for key {waiter_key}")

