    for a, b, c in itertools.product(letters, repeat=3):
        yield a + b + c

def collect_input_files(paths):
    input_files = []
    for path in paths:
        if os.path.isdir(path):
            for root, _, files in os.walk(path):
                for file in files:
                    input_files.append(os.path.join(root, file))
        else:
            input_files.append(path)
    return input_files
