using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using Studio.Wizet.Library.Wz.Util;

class Program
{
    static void Main()
    {
        string textFilePath = "input.txt";
        string stopWordsFilePath = "stopwords.txt";

        // Read the stop words from the file
        var stopWords = File.ReadAllLines(stopWordsFilePath);

        // Read the text file
        string text = File.ReadAllText(textFilePath);

        // Split the text into words
        string[] words = text.Split(new[] { ' ', '\n', '\r', '\t' }, StringSplitOptions.RemoveEmptyEntries);

        // Remove punctuation and convert to lowercase
        var cleanedWords = words.Select(w => new string(w.Where(char.IsLetter).ToArray()).ToLower());

        // Count word frequencies, ignoring stop words
        var wordFrequencies = cleanedWords
            .Where(w => !stopWords.Contains(w))
            .GroupBy(w => w)
            .Select(g => new { Word = g.Key, Count = g.Count() })
            .OrderByDescending(w => w.Count);

        // Output word frequencies
        foreach (var entry in wordFrequencies)
        {
            Console.WriteLine($"{entry.Word}: {entry.Count}");
        }
    }
}
```

In this solution, we first read the stop words from the "stopwords.txt" file and then read the text from the "input.txt" file. We then process the text to count the occurrences of each word, ignoring the stop words. Finally, we output the word frequencies in descending order.

