#include <iostream>
#include <vector>
#include <algorithm>
#include <string>

// Your function definition goes here

int main() {
    std::vector<std::string> amb_candidates = {"ambiguous_param", "AmBivalent", "candidate", "Ambidextrous"};
    std::string substring = "amb";

    int count = countSubstringMatches(amb_candidates, substring);
    std::cout << "Count of strings containing the substring: " << count << std::endl;
    return 0;
}
```

Your task is to complete the code by implementing the `countSubstringMatches` function, which takes a vector of strings `amb_candidates` and a string `substring`, and returns the count of strings in `amb_candidates` that contain the `substring` (case-insensitive).

output:
```cpp
#include <iostream>
#include <vector>
#include <algorithm>
#include <string>

int countSubstringMatches(const std::vector<std::string>& amb_candidates, const std::string& substring) {
    int count = 0;
    std::string lowerSubstring = substring;
    std::transform(lowerSubstring.begin(), lowerSubstring.end(), lowerSubstring.begin(), ::tolower);

    for (const std::string& candidate : amb_candidates) {
        std::string lowerCandidate = candidate;
        std::transform(lowerCandidate.begin(), lowerCandidate.end(), lowerCandidate.begin(), ::tolower);
        if (lowerCandidate.find(lowerSubstring) != std::string::npos) {
            count++;
        }
    }
    return count;
}

int main() {
    std::vector<std::string> amb_candidates = {"ambiguous_param", "AmBivalent", "candidate", "Ambidextrous"};
    std::string substring = "amb";

    int count = countSubstringMatches(amb_candidates, substring);
    std::cout << "Count of strings containing the substring: " << count << std::endl;
    return 0;
}
```

The `countSubstringMatches` function iterates through each candidate string, converts both the candidate and the substring to lowercase, and then checks if the lowercase candidate contains the lowercase substring. If it does, the count is incremented. Finally, the function returns the count of matches.

