from bs4 import BeautifulSoup

def parse_table_of_contents(html):
    soup = BeautifulSoup(html, 'html.parser')
    toc_dict = {}

    toc_wrapper = soup.find('div', class_='toctree-wrapper')
    if toc_wrapper:
        toc_list = toc_wrapper.find('ul')
        if toc_list:
            for item in toc_list.find_all('li', recursive=False):
                title = item.find('a').text
                sub_toc = item.find('ul')
                if sub_toc:
                    toc_dict[title] = parse_sub_toc(sub_toc)
                else:
                    toc_dict[title] = {}
    return toc_dict

def parse_sub_toc(sub_toc):
    sub_toc_dict = {}
    for item in sub_toc.find_all('li', recursive=False):
        title = item.find('a').text
        sub_sub_toc = item.find('ul')
        if sub_sub_toc:
            sub_toc_dict[title] = parse_sub_toc(sub_sub_toc)
        else:
            sub_toc_dict[title] = {}
    return sub_toc_dict
```

The `parse_table_of_contents` function uses the BeautifulSoup library to parse the HTML and extract the table of contents structure. It iterates through the list items, extracting the titles and recursively parsing any sub-table of contents. The `parse_sub_toc` function is a helper function to handle the parsing of sub-table of contents.

