    def __init__(self, search):
        self.search = search

    def iter_aggs_options(self, options):
        # Implementation of iter_aggs_options method
        for name, agg in options.items():
            yield name, agg

    def apply_aggregations(self, options):
        # Implementation of apply_aggregations method
        for name, agg in self.iter_aggs_options(options):
            # `aggs[]=` mutates `self.search`
            self.search.aggs[name] = agg if not callable(agg) else agg()

