def is_royal_flush(hand):
    return all(card in hand for card in ['A', 'K', 'Q', 'J', '10']) and len(set(suit for _, suit in hand)) == 1

def is_straight_flush(hand):
    values = sorted([card[0] for card in hand])
    return all(values[i] == values[i+1]-1 for i in range(len(values)-1)) and len(set(suit for _, suit in hand)) == 1

def is_four_of_a_kind(hand):
    values = [card[0] for card in hand]
    for value in values:
        if values.count(value) == 4:
            return True
    return False

def is_full_house(hand):
    values = [card[0] for card in hand]
    unique_values = set(values)
    if len(unique_values) == 2:
        for value in unique_values:
            if values.count(value) == 3:
                return True, value
    return False, 0

def is_flush(hand):
    return len(set(suit for _, suit in hand)) == 1

def is_straight(hand):
    values = sorted([card[0] for card in hand])
    return all(values[i] == values[i+1]-1 for i in range(len(values)-1)

def is_three_of_a_kind(hand):
    values = [card[0] for card in hand]
    for value in set(values):
        if values.count(value) == 3:
            return True
    return False

def is_two_pair(hand):
    values = [card[0] for card in hand]
    pairs = [value for value in set(values) if values.count(value) == 2]
    return len(pairs) == 2

def is_one_pair(hand):
    values = [card[0] for card in hand]
    for value in set(values):
        if values.count(value) == 2:
            return True
    return False

def crupier(hand):
    if is_royal_flush(hand):
        return 10, 0
    elif is_straight_flush(hand):
        return 9, 0
    elif is_four_of_a_kind(hand):
        return 8, 0
    elif is_full_house(hand)[0]:
        return 7, is_full_house(hand)[1]
    elif is_flush(hand):
        return 6, 0
    elif is_straight(hand):
        return 5, 0
    elif is_three_of_a_kind(hand):
        return 4, 0
    elif is_two_pair(hand):
        return 3, 0
    elif is_one_pair(hand):
        return 2, 0
    else:
        return 1, 0
