using System;
using System.Collections.Generic;

public class EventDispatcher
{
    private Dictionary<Type, List<Delegate>> eventListeners = new Dictionary<Type, List<Delegate>>();

    public void AddListener<T>(Action<T> callback)
    {
        Type eventType = typeof(T);
        if (!eventListeners.ContainsKey(eventType))
        {
            eventListeners[eventType] = new List<Delegate>();
        }
        eventListeners[eventType].Add(callback);
    }

    public void RemoveListener<T>(Action<T> callback)
    {
        Type eventType = typeof(T);
        if (eventListeners.ContainsKey(eventType))
        {
            eventListeners[eventType].Remove(callback);
        }
    }

    public void DispatchEvent<T>(T eventData)
    {
        Type eventType = typeof(T);
        if (eventListeners.ContainsKey(eventType))
        {
            foreach (Action<T> callback in eventListeners[eventType])
            {
                callback.Invoke(eventData);
            }
        }
    }

    ~EventDispatcher()
    {
        eventListeners.Clear();
    }
}

// Example usage
public class Example
{
    public static void Main()
    {
        EventDispatcher eventDispatcher = new EventDispatcher();

        eventDispatcher.AddListener<int>(OnIntEvent);
        eventDispatcher.AddListener<string>(OnStringEvent);

        eventDispatcher.DispatchEvent(10);
        eventDispatcher.DispatchEvent("Hello, World!");

        eventDispatcher.RemoveListener<int>(OnIntEvent);

        eventDispatcher.DispatchEvent(20);
    }

    private static void OnIntEvent(int value)
    {
        Console.WriteLine("Received int event: " + value);
    }

    private static void OnStringEvent(string message)
    {
        Console.WriteLine("Received string event: " + message);
    }
}
```

In this solution, the `EventDispatcher` class manages event subscriptions and unsubscriptions using a dictionary to store the event types and their corresponding callback functions. The `AddListener`, `RemoveListener`, and `DispatchEvent` methods handle the subscription, unsubscription, and triggering of events, respectively. The destructor `~EventDispatcher` ensures that event subscriptions are cleaned up when the object is being destroyed. The example usage demonstrates how to use the `EventDispatcher` class to subscribe, unsubscribe, and trigger events.

