def custom_merge(dict1: dict, dict2: dict, zip_keys: int) -> dict:
    merged_dict = {}
    keys1 = list(dict1.keys())[:zip_keys]
    keys2 = list(dict2.keys())[:zip_keys]

    for key in keys1:
        if key in dict2 and isinstance(dict1[key], list) and isinstance(dict2[key], list) and len(dict1[key]) == len(dict2[key]):
            merged_dict[key] = dict1[key] + dict2[key]
        else:
            merged_dict[key] = str(dict1[key]) + str(dict2[key])

    for key in keys2:
        if key not in keys1:
            if key in dict1 and isinstance(dict1[key], list) and isinstance(dict2[key], list) and len(dict1[key]) == len(dict2[key]):
                merged_dict[key] = dict1[key] + dict2[key]
            else:
                merged_dict[key] = str(dict1[key]) + str(dict2[key])

    return merged_dict
