import AVFoundation

class CallRecorder {
    var audioRecorder: AVAudioRecorder?

    func startRecording() {
        let audioSession = AVAudioSession.sharedInstance()
        do {
            try audioSession.setCategory(.playAndRecord, mode: .default, options: [.defaultToSpeaker])
            try audioSession.setActive(true)

            let documentsPath = FileManager.default.urls(for: .documentDirectory, in: .userDomainMask)[0]
            let audioFilename = documentsPath.appendingPathComponent("recordedCall.wav")

            let settings = [
                AVFormatIDKey: Int(kAudioFormatLinearPCM),
                AVSampleRateKey: 44100,
                AVNumberOfChannelsKey: 2,
                AVEncoderAudioQualityKey: AVAudioQuality.max.rawValue
            ]

            audioRecorder = try AVAudioRecorder(url: audioFilename, settings: settings)
            audioRecorder?.record()
        } catch {
            // Handle recording initialization errors
        }
    }

    func stopRecording() {
        audioRecorder?.stop()
    }

    func playbackRecordedCall() {
        if let audioFilename = audioRecorder?.url {
            let audioPlayer = try? AVAudioPlayer(contentsOf: audioFilename)
            audioPlayer?.play()
        }
    }
}

