function formatKeyValuePairs($inputArray, $delimiter) {
    $result = '';
    foreach ($inputArray as $key => $value) {
        if (is_array($value)) {
            if (array_values($value) === $value) {
                $result .= $key . $delimiter . implode(', ', $value) . "\n";
            } else {
                foreach ($value as $subKey => $subValue) {
                    $result .= $key . $delimiter . formatKeyValuePairs([$subKey => $subValue], ':');
                }
            }
        } else {
            $result .= $key . $delimiter . $value . "\n";
