class PreConditionError(Exception):
    pass

def pre(condition):
    def decorator(func):
        def wrapper(*args, **kwargs):
            if not condition(*args, **kwargs):
                raise PreConditionError("Precondition not met")
            return func(*args, **kwargs)
        return wrapper
    return decorator

# Example usage
@pre(lambda x: x > 0)
def f(x):
    return x + 1

# Validate the precondition
try:
    f(-1)  # This should raise a PreConditionError
except PreConditionError as e:
    print(e)  # Output: Precondition not met
```

