                    await user.edit(mute=True, reason=time_and_reason.reason)
                    await ctx.send(f'{user.display_name} has been muted for {time_and_reason.duration} minutes.')
                    await asyncio.sleep(time_and_reason.duration * 60)
                    await user.edit(mute=False, reason='Mute duration expired')
                    await ctx.send(f'{user.display_name} has been unmuted.')
                else:
                    await user.edit(mute=True, reason=time_and_reason.reason)
                    await ctx.send(f'{user.display_name} has been permanently muted.')
            else:
                await ctx.send(f'{user.display_name} is not in a voice channel.')
        else:
            await ctx.send('You do not have permission to mute members.')
