def queryable(func):
    def wrapper(dest_func, _body, kwargs):
        query = kwargs.pop("query", None)
        ret = func(dest_func, _body, kwargs)
        try:
            return jmespath.search(query, ret) if query else ret
        except jmespath.exceptions.ParseError:
            # Handle parse error
            return None

def execute_queryable(operation_map, operation_name, **kwargs):
    if operation_name in operation_map:
        operation_func = operation_map[operation_name]
        result = operation_func(None, kwargs)
        if "query" in kwargs:
            query = kwargs["query"]
            try:
                return jmespath.search(query, result)
            except jmespath.exceptions.ParseError:
                # Handle parse error
                return None
        else:
            return result
    else:
        return None  # Handle invalid operation name
