class Node:
    def __init__(self, value):
        self.value = value
        self.next = None

class LinkedListStack:
    def __init__(self):
        self.head = None

    def push(self, value):
        new_node = Node(value)
        new_node.next = self.head
        self.head = new_node

    def pop(self):
        if self.head is None:
            return None
        else:
            popped_value = self.head.value
            self.head = self.head.next
            return popped_value

    def peek(self):
        if self.head is None:
            return None
        else:
            return self.head.value

    def is_empty(self):
        return self.head is None

if __name__ == '__main__':
    list_stack = LinkedListStack()
    list_stack.push(5)
    list_stack.push(10)
    list_stack.push(15)
    print(list_stack.peek())  # Output: 15
    print(list_stack.pop())   # Output: 15
    print(list_stack.peek())  # Output: 10
    print(list_stack.is_empty())  # Output: False
    print(list_stack.pop())   # Output: 10
    print(list_stack.pop())   # Output: 5
    print(list_stack.is_empty())  # Output: True
    print(list_stack.pop())   # Output: None
```

